diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index bdd5311ab55ad..dd2c753a84ec9 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -272,6 +272,16 @@ static cl::opt<bool> PerLaneGatherScale(
     cl::desc("Use per-lane execution scale for gather/buildvector tree "
              "entries to model LICM-hoistable buildvector sequences."));

+static cl::opt<bool> EnableSLPStoreLoadForwardCheck(
+    "slp-store-load-forward-check", cl::init(true), cl::Hidden,
+    cl::desc("Check for store-to-load forwarding conflicts in SLP"));
+
+static cl::opt<unsigned> SLPStlfLoopSizeThreshold(
+    "slp-stlf-loop-size-threshold", cl::init(128), cl::Hidden,
+    cl::desc("Maximum loop body size (instructions) for SLP store-to-load "
+             "forwarding conflict check; larger loops amortize the stall and "
+             "are skipped"));
+
 // Limit the number of alias checks. The limit is chosen so that
 // it has no negative effect on the llvm benchmarks.
 static const unsigned AliasedCheckLimit = 10;
@@ -27154,6 +27164,128 @@ bool SLPVectorizerPass::runImpl(Function &F, ScalarEvolution *SE_,
   return Changed;
 }

+bool SLPVectorizerPass::hasStoreLoadForwardingConflict(ArrayRef<Value *> Chain,
+                                                       unsigned VF) {
+  if (Chain.empty())
+    return false;
+
+  auto *FirstStore = cast<StoreInst>(Chain[0]);
+  BasicBlock *BB = FirstStore->getParent();
+
+  Loop *L = LI->getLoopFor(BB);
+  if (!L) {
+    LLVM_DEBUG(dbgs() << "SLP: STLF check: stores not in a loop, skipping\n");
+    return false;
+  }
+
+  Type *ValueTy = FirstStore->getValueOperand()->getType();
+  TypeSize StoreSize = DL->getTypeStoreSize(ValueTy);
+  // SLP only handles fixed-width vectors; bail out on scalable types.
+  if (StoreSize.isScalable())
+    return false;
+  uint64_t ElementSize = StoreSize.getFixedValue();
+  // Defensive: zero-sized store types would cause division by zero below.
+  if (ElementSize == 0)
+    return false;
+  uint64_t VectorStoreBytes = uint64_t(VF) * ElementSize;
+  LLVM_DEBUG(dbgs() << "SLP: STLF check: VF=" << VF
+                    << " ElementSize=" << ElementSize
+                    << " VectorStoreBytes=" << VectorStoreBytes << "\n");
+
+  // Threshold for "store still hot in the store buffer". Mirrors
+  // LoopAccessAnalysis::couldPreventStoreLoadForward; the value is
+  // `8 * ElementSize` so that comparing `Distance / VectorStoreBytes`
+  // (number of vector-store-width slots between store and load) against
+  // it yields the same effective bound as LAA's check.
+  const uint64_t NumItersForSafety = uint64_t(8) * ElementSize;
+
+  // Heuristic: if the loop body is large, the STLF stall is amortized by
+  // other computation. Don't reject vectorization in that case. Skip
+  // debug/pseudo intrinsics so that compiling with -g does not
+  // artificially inflate the count.
+  unsigned LoopBodySize = 0;
+  for (BasicBlock *LoopBB : L->blocks())
+    for (const Instruction &I : *LoopBB)
+      if (!I.isDebugOrPseudoInst())
+        ++LoopBodySize;
+
+  LLVM_DEBUG(dbgs() << "SLP: STLF check: loop body size=" << LoopBodySize
+                    << " threshold=" << SLPStlfLoopSizeThreshold << "\n");
+  if (LoopBodySize > SLPStlfLoopSizeThreshold) {
+    LLVM_DEBUG(dbgs() << "SLP: STLF check: loop too large, skipping\n");
+    return false;
+  }
+
+  Value *StorePtr = FirstStore->getPointerOperand();
+
+  // Scan loads in the store's parent basic block that access the same
+  // underlying object. Loads in other blocks of the loop may also conflict
+  // but are conservatively ignored here (extending the scan to all loop
+  // blocks is left as a follow-up).
+  Value *StoreBase = getUnderlyingObject(StorePtr);
+  LLVM_DEBUG(dbgs() << "SLP: STLF check: StorePtr=" << *StorePtr
+                    << " StoreBase=" << *StoreBase << "\n");
+
+  for (Instruction &I : *BB) {
+    auto *LdI = dyn_cast<LoadInst>(&I);
+    if (!LdI || !LdI->isSimple())
+      continue;
+
+    Value *LoadPtr = LdI->getPointerOperand();
+    Value *LoadBase = getUnderlyingObject(LoadPtr);
+    if (LoadBase != StoreBase) {
+      LLVM_DEBUG(dbgs() << "SLP: STLF: load base mismatch, skipping\n");
+      continue;
+    }
+
+    LLVM_DEBUG(dbgs() << "SLP: STLF: found same-base load: " << *LdI << "\n");
+
+    std::optional<int64_t> Diff = getPointersDiff(
+        ValueTy, StorePtr, LdI->getType(), LoadPtr, *DL, *SE,
+        /*StrictCheck=*/false, /*CheckType=*/false);
+    if (!Diff) {
+      LLVM_DEBUG(dbgs() << "SLP: STLF: getPointersDiff returned nullopt\n");
+      continue;
+    }
+
+    // Only negative diffs indicate backward loop-carried dependences
+    // (load reads from earlier array positions written by recent iterations).
+    // Positive diffs are forward references within the same iteration that
+    // will also be vectorized, so STLF is not a concern.
+    if (*Diff >= 0) {
+      LLVM_DEBUG(dbgs() << "SLP: STLF: diff=" << *Diff
+                        << " (forward, skipping)\n");
+      continue;
+    }
+
+    uint64_t Distance = -static_cast<uint64_t>(*Diff) * ElementSize;
+    LLVM_DEBUG(dbgs() << "SLP: STLF: diff=" << *Diff
+                      << " distance=" << Distance << "\n");
+
+    // Skip loads that are too close to the store chain start: they read from
+    // addresses before the vector store region [StorePtr, StorePtr + VF) and
+    // do not overlap with the widened store, so no STLF issue.
+    if (Distance < VectorStoreBytes)
+      continue;
+
+    // Check if the distance would cause misalignment with vector stores.
+    // If Distance % VectorStoreBytes != 0, loads will straddle two vector
+    // stores. If the distance is also short (store still in store buffer),
+    // this causes STLF failures.
+    if (Distance % VectorStoreBytes != 0 &&
+        Distance / VectorStoreBytes < NumItersForSafety) {
+      LLVM_DEBUG(dbgs() << "SLP: Store-load forwarding conflict: distance "
+                        << Distance << " bytes, vector store width "
+                        << VectorStoreBytes
+                        << " bytes, misalignment "
+                        << (Distance % VectorStoreBytes) << "\n");
+      return true;
+    }
+  }
+
+  return false;
+}
+
 std::optional<bool>
 SLPVectorizerPass::vectorizeStoreChain(ArrayRef<Value *> Chain, BoUpSLP &R,
                                        unsigned Idx, unsigned MinVF,
@@ -27175,6 +27307,21 @@ SLPVectorizerPass::vectorizeStoreChain(ArrayRef<Value *> Chain, BoUpSLP &R,
       return false;
   }

+  // Early bail-out: reject chains that would suffer STLF stalls before doing
+  // expensive tree analysis (buildTree, reorder, getTreeCost, etc.).
+  if (EnableSLPStoreLoadForwardCheck &&
+      hasStoreLoadForwardingConflict(Chain, VF)) {
+    LLVM_DEBUG(dbgs() << "SLP: Skipping store chain due to potential "
+                         "store-to-load forwarding conflict\n");
+    using namespace ore;
+    R.getORE()->emit(
+        OptimizationRemarkMissed(SV_NAME, "StoreLoadForwardConflict",
+                                 cast<StoreInst>(Chain[0]))
+        << "Stores not SLP vectorized: short loop-carried dependence "
+           "distance could cause store-to-load forwarding stalls");
+    return false;
+  }
+
   LLVM_DEBUG(dbgs() << "SLP: Analyzing " << VF << " stores at offset " << Idx
                     << "\n");
